// Time:  O(n)
// Space: O(1)

class Solution {
public:
    int minOperations(string s) {
        int cnt = 0;
        for (int i = 0; i < size(s); ++i) {
            if (s[i] - '0' == i % 2) {
                ++cnt;
            }
        }
        return min(cnt, int(size(s)) - cnt);
    }
};

# Time:  O(n)
# Space: O(1)

class Solution(object):
    def minOperations(self, s):
        """
        :type s: str
        :rtype: int
        """
        cnt = sum(int(c) == i%2 for i, c in enumerate(s))
        return min(cnt, len(s)-cnt)
